import boto3
from botocore import exceptions

def list_files(bucket, access_key, secret_key):
    try:
        s3 = boto3.client('s3', aws_access_key_id=access_key, 
                          aws_secret_access_key=secret_key)
        
        files = []
        for obj in s3.list_objects(Bucket=bucket)['Contents']:
            files.append(obj['Key'])
            
        return files
    
    except exceptions.NoCredentialsError as e:
        print("Missing Credentials :", e)
        
    except exceptions.BotoCoreError as e:
        print("AWS Error :", e)

files = list_files('demo-bucket', 'AKIA123EXAMPLE', 
                   'wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY')

